3	export const test = base.extend({
4	  page: async ({ page, baseURL, context }, use) => {
5	    const localOrigin = baseURL ? new URL(baseURL).origin : undefined;
6	    const isSpecialScheme = (url: string) =>
7	      url.startsWith("about:") ||
8	      url.startsWith("blob:") ||
9	      url.startsWith("data:");
10	
11	    await context.route("**/*", async (route) => {
12	      const requestUrl = route.request().url();
13	      if (!localOrigin || isSpecialScheme(requestUrl)) {
14	        await route.continue();
15	        return;
16	      }
17	
18	      const requestOrigin = new URL(requestUrl).origin;
19	      if (requestOrigin === localOrigin) {
20	        await route.continue();
21	        return;
22	      }
23	
24	      await route.abort();
25	      throw new Error(
26	        `[Playwright] Blocked external browser request: ${route.request().method()} ${requestUrl}\n All requests to external APIs must flow through server functions`,
27	      );
28	    });
29	
30	    await use(page);
31	    await context.unroute("**/*");
32	  },
33	});
