5	export function setupRequestMocking() {
6	  const mockHandler = createHandler(() => {
7	    // Read and return headers of the incoming HTTP request for every render.
8	    return getRequestHeaders();
9	  });
10	
11	  // Type mismatch stems from MSW's split type declarations (core vs node). Safe to cast.
12	  const mswServer = setupServer(
13	    // we have to cast this because of how the lib exports commonjs vs esm and
14	    // onlyt he __type property is incompatible
15	    mockHandler as unknown as Parameters<typeof setupServer>[0],
16	  );
17	  mswServer.listen({
18	    onUnhandledRequest(request) {
19	      console.error(
20	        `[MSW] Unhandled request: ${request.method} ${request.url}`,
21	      );
22	      throw new Error(
23	        `[MSW] Unhandled request: ${request.method} ${request.url}`,
24	      );
25	    },
26	  });
27	}
