3	type BrowserRequestGuardOptions = {
4	  allowedOrigins?: string[];
5	};
6	
7	declare global {
8	  interface Window {
9	    __publicPagesMswWorker?: ReturnType<typeof setupWorker>;
10	  }
11	}
12	
13	function toOrigin(url: string) {
14	  return new URL(url).origin;
15	}
16	
17	export async function startBrowserRequestGuard(
18	  options: BrowserRequestGuardOptions = {},
19	) {
20	  if (window.__publicPagesMswWorker) {
21	    return;
22	  }
23	
24	  const worker = setupWorker();
25	  const allowedOrigins = new Set([
26	    window.location.origin,
27	    ...(options.allowedOrigins ?? []),
28	  ]);
29	
30	  await worker.start({
31	    quiet: true,
32	    onUnhandledRequest({ method, url }) {
33	      const requestOrigin = toOrigin(url);
34	      if (allowedOrigins.has(requestOrigin)) {
35	        return;
36	      }
37	
38	      throw new Error(
39	        `[MSW] Blocked external browser request: ${method} ${url}\n All requests to external APIs must flow through server functions`,
40	      );
41	    },
42	  });
43	
44	  window.__publicPagesMswWorker = worker;
45	}
